local Players = game:GetService("Players")
local HttpService = game:GetService("HttpService")
local player = Players.LocalPlayer
local playerGui = player:WaitForChild("PlayerGui")

local currentGRID = 32
local currentTOTAL = 1024
local isPlayingVideo = false
local remote = game.ReplicatedStorage:FindFirstChild("UpdateBoard") or game.Workspace:FindFirstChild("UpdateBoard", true)

local function decodeRLE(encoded)
    local flat = {}
    local idx = 1
    for _, pair in ipairs(encoded) do
        local val = pair[1] or 0
        local count = pair[2] or 1
        for _ = 1, count do
            flat[idx] = val
            idx += 1
        end
    end
    return flat
end

local function playBadApple()
    if isPlayingVideo then isPlayingVideo = false return end
    isPlayingVideo = true
    
    local data = HttpService:JSONDecode(videoRawData)
    local videoData = data.frames or data.video
    
    local frameNum = 1
    while isPlayingVideo and frameNum <= #videoData do
        local flatFrame = decodeRLE(videoData[frameNum])
        local batch = {}
        local count = 0
        
        for i = 1, currentTOTAL do
            local val = flatFrame[i] or 0
            local hex = (val < 128) and "000000" or "FFFFFF"
            -- Ajuste o calculo de index se necessário
            batch[tostring(i)] = hex 
            count = count + 1
            if count >= 64 then
                pcall(function() remote:InvokeServer(batch) end)
                batch = {}
                count = 0
                task.wait(0.005)
            end
        end
        if count > 0 then pcall(function() remote:InvokeServer(batch) end) end
        
        frameNum = frameNum + 1
        if frameNum > #videoData then frameNum = 1 end
        task.wait(0.03)
    end
end

-- Botão simples para testar
local sg = Instance.new("ScreenGui", playerGui)
local b = Instance.new("TextButton", sg)
b.Size = UDim2.new(0, 200, 0, 50)
b.Position = UDim2.new(0.5, -100, 0.5, -25)
b.Text = "PLAY BAD APPLE (LOCAL DATA)"
b.MouseButton1Click:Connect(playBadApple)

